use strict;
use warnings;

my $text = "Merhaba dunya bu bir test metni. Bu metin kelime sayma icin kullanilacak. Merhaba tekrar!";

# Noktalama isaretlerini temizle
(my $clean_text = $text) =~ s/[.,!]//g;
my @words = split /\s+/, lc($clean_text);

print "Toplam kelime sayisi: " . scalar(@words) . "\n";
print "Toplam karakter sayisi: " . length($text) . "\n";

# Kelime frekansi
my %word_count;
$word_count{$_}++ for @words;

print "\nKelime frekanslari:\n";
foreach my $word (sort { $word_count{$b} <=> $word_count{$a} } keys %word_count) {
    print "'$word': $word_count{$word} kez\n";
}

# En uzun kelime
my $longest_word = "";
foreach my $word (@words) {
    $longest_word = $word if length($word) > length($longest_word);
}
print "\nEn uzun kelime: '$longest_word' (" . length($longest_word) . " karakter)\n";

# Ortalama kelime uzunlugu
my $total_length = 0;
$total_length += length($_) for @words;
my $avg_length = $total_length / scalar(@words);
printf "Ortalama kelime uzunlugu: %.2f\n", $avg_length;
